package ratelimiter

import (
	"sync"
	"time"
)

// realClock implements Clock using the actual system time.
type realClock struct{}

func (rc *realClock) Now() time.Time { return time.Now() }

// bucket stores per‑key token bucket state.
type bucket struct {
	tokens float64   // available tokens (may be fractional)
	last   time.Time // last time tokens were refilled
}

// limiterImpl implements the Limiter interface using a token bucket algorithm.
type limiterImpl struct {
	cfg     Config
	clock   Clock
	mu      sync.Mutex
	buckets map[string]*bucket
}

// newLimiter creates a new token‑bucket rate limiter.
// If clock is nil, the real system clock is used.
func newLimiter(cfg Config, clock Clock) Limiter {
	if clock == nil {
		clock = &realClock{}
	}
	// Default Burst to Rate when not explicitly set.
	if cfg.Burst == 0 {
		cfg.Burst = cfg.Rate
	}
	return &limiterImpl{
		cfg:     cfg,
		clock:   clock,
		buckets: make(map[string]*bucket),
	}
}

// refill updates the token count for a bucket based on elapsed time.
func (l *limiterImpl) refill(b *bucket, now time.Time) {
	elapsed := now.Sub(b.last).Seconds()
	if elapsed <= 0 {
		return
	}
	// Tokens added per second = Rate / Window.Seconds()
	ratePerSec := float64(l.cfg.Rate) / l.cfg.Window.Seconds()
	b.tokens += elapsed * ratePerSec
	if b.tokens > float64(l.cfg.Burst) {
		b.tokens = float64(l.cfg.Burst)
	}
	b.last = now
}

// Allow checks whether a request for the given key can proceed.
// It consumes one token when allowed.
func (l *limiterImpl) Allow(key string) bool {
	now := l.clock.Now()

	l.mu.Lock()
	defer l.mu.Unlock()

	b, ok := l.buckets[key]
	if !ok {
		// First request for this key: start with a full burst and consume one token.
		l.buckets[key] = &bucket{
			tokens: float64(l.cfg.Burst) - 1,
			last:   now,
		}
		return true
	}

	// Refill tokens based on elapsed time.
	l.refill(b, now)

	if b.tokens >= 1 {
		b.tokens -= 1
		return true
	}
	return false
}

// Reset clears the rate‑limiting state for the specified key.
func (l *limiterImpl) Reset(key string) {
	l.mu.Lock()
	defer l.mu.Unlock()
	delete(l.buckets, key)
}
EOF
